class Solution:
    def minimumCost(self, s: str) -> int:
        import heapq
        n = len(s)
        start_state = tuple(int(c) for c in s)
        targets = {tuple([0] * n), tuple([1] * n)}
        if start_state in targets:
            return 0
        dist = {start_state: 0}
        pq = [(0, start_state)]
        while pq:
            d, state = heapq.heappop(pq)
            if d > dist.get(state, float('inf')):
                continue
            if state in targets:
                return d
            for i in range(n - 1):
                new_state = list(state)
                for k in range(i + 1):
                    new_state[k] ^= 1
                new_state = tuple(new_state)
                nd = d + (i + 1)
                if nd < dist.get(new_state, float('inf')):
                    dist[new_state] = nd
                    heapq.heappush(pq, (nd, new_state))
                new_state2 = list(state)
                for k in range(i + 1, n):
                    new_state2[k] ^= 1
                new_state2 = tuple(new_state2)
                nd2 = d + (n - i - 1)
                if nd2 < dist.get(new_state2, float('inf')):
                    dist[new_state2] = nd2
                    heapq.heappush(pq, (nd2, new_state2))
        return min(dist.get(t, float('inf')) for t in targets)

